import AddOutlined from '@universe-design/icons-react/AddOutlined';
import clsx from 'clsx';
import React from 'react';
import { forwardHTMLRef } from '../../util/forwardRef';
import { useUploadContext } from '../hooks/UploadContext';
import type { UploadTriggerProps } from '../UploadTrigger';
import { UploadTrigger } from '../UploadTrigger';

export const PictureUploadTrigger = forwardHTMLRef<UploadTriggerProps, 'div'>((props, ref) => {
  const { accept, multiple, directory, type, openFileDialogOnClick, ...restProps } = props;
  const { disabled, rootPrefixCls } = useUploadContext();

  const triggerClasses = {
    [`${rootPrefixCls}-picture-upload-trigger`]: true,
    [`${rootPrefixCls}-picture-upload-trigger--disabled`]: disabled,
    [`${rootPrefixCls}-picture-upload-trigger--active`]: !disabled,
  };

  return (
    <UploadTrigger
      accept={accept}
      multiple={multiple}
      directory={directory}
      type={type}
      openFileDialogOnClick={openFileDialogOnClick}
    >
      <div className={clsx(triggerClasses)} data-testid="picture-upload-trigger" ref={ref} {...restProps}>
        <AddOutlined />
      </div>
    </UploadTrigger>
  );
});
